// Template-ready Spotify Track URL -> Track URI converter
// -------------------------------------------------------
// What this node does:
// - Reads a Spotify track link (or a spotify:track:... URI) from the incoming item
// - Extracts the 22-character track ID
// - Outputs item.json.track_uri in the format: spotify:track:<trackId>
//
// How to use in your own template:
// 1) Ensure your trigger provides a field containing the Spotify track URL/URI.
// 2) Set INPUT_FIELD_NAME below to match that field name.
// 3) Downstream nodes can reference: {{$json.track_uri}}
//
// Supported inputs:
// - https://open.spotify.com/track/<trackId>?...
// - spotify:track:<trackId>
//
// Not supported without an extra HTTP step:
// - https://spoti.fi/<short>  (short URLs are redirects; you must expand them first)

const INPUT_FIELD_NAME = 'Spotify track URL'; // Change to your incoming field name if needed

const items = $input.all();

for (const item of items) {
  // Read URL/URI from the expected field, plus a few common fallbacks
  const source =
    item.json[INPUT_FIELD_NAME] ??
    item.json.url ??
    item.json.spotifyUrl ??
    item.json.spotify_track_url;

  if (!source) {
    throw new Error(
      `Missing Spotify track input. Expected a field named "${INPUT_FIELD_NAME}" (or one of the fallbacks: url, spotifyUrl, spotify_track_url).`
    );
  }

  // Extract the track ID (22 base62 chars)
  const match =
    String(source).match(/open\.spotify\.com\/track\/([A-Za-z0-9]{22})/) ||
    String(source).match(/^spotify:track:([A-Za-z0-9]{22})$/);

  if (!match) {
    if (String(source).includes('spoti.fi/')) {
      throw new Error(
        'Short Spotify URL detected (spoti.fi). Add an HTTP Request node to follow redirects and obtain the final open.spotify.com URL before this node.'
      );
    }
    throw new Error('Invalid Spotify track URL/URI. Could not find a 22-character track ID.');
  }

  const trackId = match[1];
  item.json.track_uri = `spotify:track:${trackId}`;
}

return items;
